export function getOilBySlug(slug: string): OilEntry | undefined {
  return oilsData.find(oil => oil.slug === slug);
}

export function getOilsByCategory(category: OilCategory): OilEntry[] {
  return oilsData.filter(oil => oil.category === category);
}

export function searchOils(query: string): OilEntry[] {
  const q = query.toLowerCase();
  return oilsData.filter(oil =>
    oil.name.toLowerCase().includes(q) ||
    oil.nameEn.toLowerCase().includes(q) ||
    oil.description.toLowerCase().includes(q) ||
    oil.subcategory.toLowerCase().includes(q) ||
    (oil.milSpec?.toLowerCase().includes(q)) ||
    (oil.natoCode?.toLowerCase().includes(q)) ||
    (oil.tags?.some(t => t.toLowerCase().includes(q)))
  );
}

export const oilsCount = oilsData.length;
